package com.example.lessondesign.controller; import com.example.lessondesign.bean.ImageResource; import com.example.lessondesign.dao.ImageResourceDao; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; import java.util.*; @RestController @RequestMapping("/api/resources") public class ResourceLibraryController { @Autowired private ImageResourceDao dao; @GetMapping("/library") public ResponseEntity<Map<String,Object>> getLibrary(@RequestParam(defaultValue="0") int page, @RequestParam(defaultValue="10") int size){ int offset=page*size; List<ImageResource> list=dao.selectAll(offset,size); int total=dao.countAll(); Map<String,Object> r=new HashMap<>();r.put("resources",list);r.put("currentPage",page);r.put("totalItems",total); return ResponseEntity.ok(r); } }